import{_ as r,o as t,c as n,j as e,a as o,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"心灵塑师的异能","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/4.术法/魔法/法术书/心灵塑师/心灵塑师的异能.md","filePath":"4.资源分区/4.术法/魔法/法术书/心灵塑师/心灵塑师的异能.md"}'),p={name:"4.资源分区/4.术法/魔法/法术书/心灵塑师/心灵塑师的异能.md"};function d(_,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"心灵塑师的异能",tabindex:"-1"},[o("心灵塑师的异能 "),e("a",{class:"header-anchor",href:"#心灵塑师的异能","aria-label":'Permalink to "心灵塑师的异能"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序001")])])],-1),s('<h1 id="心灵塑师的异能-1" tabindex="-1">心灵塑师的异能 <a class="header-anchor" href="#心灵塑师的异能-1" aria-label="Permalink to &quot;心灵塑师的异能&quot;">​</a></h1><p>反击（Counter）<br> 反击法术允许使用者去反击其他的法术，让它不能生效。这种法术必须在目标法术使用过程中，使用反射动作去调用一个可调用的标准动作以进行这次反击。如果一道法术被成功反击了，那么它的效果将完全无效化。一般而言，某个等级的反击法术只能反击最多等同于同级及以下等级的法术，并且只能反击检定时主专业为心智系、副专业为互动系的法术。进行一次反击使用智力-学识-专业：施法-辅助专业：反击（洞察）进行检定，若检定出目大于施法者检定出目，则成功反击，无效那道法术。</p><p>风暴（Storm）<br> 当你施放具有风暴特性的法术时，本场景内于它之前每施放过一个法术，便将此法术复制一次，在一道拥有风暴特性的法术使用过后，风暴计数清零。风暴计数会随着使用的法术等级提升而获得更多计（D1C2B4A8S16）</p><p>通联古咒X（Spilce onto Arcane）<br> 于施法者使用一道类别为古咒的法术时，可以再支付X点对应法术力，将一道非释放法术的，拥有通联古咒特性的法术效果加入那次施法中，释放一次古咒中能使用的通联古咒数量不限，但不可重复，会正常计算风暴计数</p><p>命悬一刻（Fateful hour）<br> 前提为施法者濒死状态时使用可以触发的效果</p><p>延缓X（Suspend）<br> 当某一道法术以延缓X的形式结算时，它将会在X个回合后被立即释放出来（而非行动轮），被释放时会正常结算它的效果，视作插入结算</p><hr><p>Copyright © 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const u=r(p,[["render",d]]);export{f as __pageData,u as default};
